import json
import time

import pytest

from .conftest import seed_member, seed_dnd


# ---------------------------------------------------------------------------
# REQ-001 — end-to-end mention dispatch over all four surfaces
# ---------------------------------------------------------------------------

def test_send_message_with_mention_dispatches_all_four_surfaces_end_to_end(http_client, db, realtime_listener):
    """REQ-001: POST /api/messages with @m1 → push+banner+sound+badge fire end-to-end."""
    seed_member(db, "m1", channels=["c1"])
    seed_member(db, "m99", channels=["c1"])
    seed_dnd(db, "m1", manual_on=False)

    resp = http_client.post("/api/messages", json={
        "channel_id": "c1",
        "author_id": "m99",
        "body": "hey @m1",
        "mention_ids": ["m1"],
        "mention_kind": "individual",
    })
    assert resp.status_code == 200

    # Side effect 1: in-app banner channel sees the fire event.
    msg = realtime_listener.get_message(timeout=2.0)
    while msg and msg["type"] != "message":
        msg = realtime_listener.get_message(timeout=2.0)
    assert msg is not None
    payload = json.loads(msg["data"])
    assert payload["kind"] == "banner.fire"
    assert payload["mentioned_id"] == "m1"

    # Side effect 2: DB shows unread_badge_count + unread_mention_count incremented.
    row = db.execute(
        "SELECT unread_badge_count, unread_mention_count FROM member_counters WHERE member_id = %s",
        ["m1"],
    ).fetchone()
    assert row[0] >= 1
    assert row[1] >= 1

    # Side effect 3: push fan-out row recorded with successful_surfaces non-empty.
    dispatch_row = db.execute(
        "SELECT successful_surfaces FROM mention_dispatch WHERE mentioned_id = %s ORDER BY created_at DESC LIMIT 1",
        ["m1"],
    ).fetchone()
    assert dispatch_row is not None
    surfaces = set(dispatch_row[0])
    # At least one must fire per REQ-001 "delivered when ≥1 surface fires".
    assert surfaces, "no surface marked successful"


# ---------------------------------------------------------------------------
# REQ-002 — DND silences external dispatch but increments badge
# ---------------------------------------------------------------------------

def test_mention_under_dnd_increments_badge_but_no_external_dispatch_observed(http_client, db, realtime_listener):
    """REQ-002: WHILE DND active → no push/banner/sound dispatched externally,
    but badge & unread_mention_count both increment in DB."""
    seed_member(db, "m1", channels=["c1"])
    seed_member(db, "m99", channels=["c1"])
    seed_dnd(db, "m1", manual_on=True)

    resp = http_client.post("/api/messages", json={
        "channel_id": "c1",
        "author_id": "m99",
        "body": "hey @m1",
        "mention_ids": ["m1"],
        "mention_kind": "individual",
    })
    assert resp.status_code == 200

    # No banner-fire event on realtime channel.
    drained = []
    deadline = time.time() + 1.5
    while time.time() < deadline:
        m = realtime_listener.get_message(timeout=0.2)
        if m and m["type"] == "message":
            drained.append(json.loads(m["data"]))
    fire_events = [e for e in drained if e.get("kind") == "banner.fire"]
    assert fire_events == [], f"banner fired despite DND: {fire_events}"

    # Badge & mention count still incremented.
    row = db.execute(
        "SELECT unread_badge_count, unread_mention_count FROM member_counters WHERE member_id = %s",
        ["m1"],
    ).fetchone()
    assert row[0] >= 1
    assert row[1] >= 1


# ---------------------------------------------------------------------------
# REQ-005 — edit adding a mention dispatches only the newly added recipient
# ---------------------------------------------------------------------------

def test_edit_adding_mention_dispatches_new_recipient_only(http_client, db, realtime_listener):
    """REQ-005: PATCH message → REQ-001 pipeline runs only for newly-added m2."""
    seed_member(db, "m1", channels=["c1"])
    seed_member(db, "m2", channels=["c1"])
    seed_member(db, "m99", channels=["c1"])

    create = http_client.post("/api/messages", json={
        "channel_id": "c1", "author_id": "m99",
        "body": "hey @m1", "mention_ids": ["m1"],
        "mention_kind": "individual",
    })
    assert create.status_code == 200
    msg_id = create.json()["id"]

    # Drain any events from the create.
    deadline = time.time() + 1.0
    while time.time() < deadline:
        realtime_listener.get_message(timeout=0.1)

    # Now PATCH to add @m2.
    patch = http_client.patch(f"/api/messages/{msg_id}", json={
        "body": "hey @m1 @m2",
        "mention_ids": ["m1", "m2"],
    })
    assert patch.status_code == 200

    # Collect fire events from the edit.
    fires = []
    deadline = time.time() + 2.0
    while time.time() < deadline:
        m = realtime_listener.get_message(timeout=0.2)
        if m and m["type"] == "message":
            payload = json.loads(m["data"])
            if payload.get("kind") == "banner.fire":
                fires.append(payload["mentioned_id"])

    assert "m2" in fires, "newly-added m2 was not dispatched"
    assert "m1" not in fires, "already-mentioned m1 was re-dispatched"


# ---------------------------------------------------------------------------
# REQ-006 — delete retracts in-app banner via realtime channel
# ---------------------------------------------------------------------------

def test_delete_message_retracts_in_app_banner_via_realtime_channel(http_client, db, realtime_listener):
    """REQ-006: DELETE → realtime channel emits a banner.retract for unopened banners."""
    seed_member(db, "m1", channels=["c1"])
    seed_member(db, "m99", channels=["c1"])

    create = http_client.post("/api/messages", json={
        "channel_id": "c1", "author_id": "m99",
        "body": "hey @m1", "mention_ids": ["m1"],
        "mention_kind": "individual",
    })
    msg_id = create.json()["id"]

    # Drain create-side events.
    deadline = time.time() + 1.0
    while time.time() < deadline:
        realtime_listener.get_message(timeout=0.1)

    delete = http_client.delete(f"/api/messages/{msg_id}")
    assert delete.status_code == 200

    # Expect a banner.retract event for this message.
    retract_events = []
    deadline = time.time() + 2.0
    while time.time() < deadline:
        m = realtime_listener.get_message(timeout=0.2)
        if m and m["type"] == "message":
            payload = json.loads(m["data"])
            if payload.get("kind") == "banner.retract":
                retract_events.append(payload)

    assert any(e.get("message_id") == msg_id for e in retract_events), \
        f"no banner.retract for {msg_id}: got {retract_events}"

    # Push & badge unchanged — verified via DB.
    badge = db.execute(
        "SELECT unread_badge_count FROM member_counters WHERE member_id = %s", ["m1"],
    ).fetchone()
    assert badge[0] >= 1, "badge was decremented on delete"


# ---------------------------------------------------------------------------
# REQ-007 — DND window expiry must not resurface
# ---------------------------------------------------------------------------

def test_dnd_window_expiry_does_not_trigger_resurfacing_dispatch(http_client, db, realtime_listener):
    """REQ-007: PUT /api/members/:id/dnd → off after a backlog → 0 retro dispatches."""
    seed_member(db, "m1", channels=["c1"])
    seed_member(db, "m99", channels=["c1"])
    seed_dnd(db, "m1", manual_on=True)

    # Accumulate 3 silenced mentions.
    for i in range(3):
        http_client.post("/api/messages", json={
            "channel_id": "c1", "author_id": "m99",
            "body": f"backlog @m1 #{i}", "mention_ids": ["m1"],
            "mention_kind": "individual",
        })
    # Drain everything; under DND none of these should have produced banner.fires anyway.
    deadline = time.time() + 1.0
    while time.time() < deadline:
        realtime_listener.get_message(timeout=0.1)

    # Now flip DND off.
    resp = http_client.put("/api/members/m1/dnd", json={"manual_on": False})
    assert resp.status_code == 200

    # Wait a beat and collect events.
    deadline = time.time() + 2.0
    fires = []
    while time.time() < deadline:
        m = realtime_listener.get_message(timeout=0.2)
        if m and m["type"] == "message":
            payload = json.loads(m["data"])
            if payload.get("kind") == "banner.fire" and payload.get("mentioned_id") == "m1":
                fires.append(payload)

    assert fires == [], f"resurfacing occurred on DND end: {fires}"


# ---------------------------------------------------------------------------
# REQ-002 — broadcast @channel under DND still suppresses push
# ---------------------------------------------------------------------------

def test_broadcast_at_channel_under_dnd_does_not_dispatch_push(http_client, db):
    """REQ-002 ext: @channel broadcast under DND → no push for DND members."""
    seed_member(db, "m1", channels=["c1"])
    seed_member(db, "m2", channels=["c1"])
    seed_member(db, "m99", channels=["c1"])
    seed_dnd(db, "m1", manual_on=True)   # m1 is in DND
    seed_dnd(db, "m2", manual_on=False)  # m2 is not

    resp = http_client.post("/api/messages", json={
        "channel_id": "c1", "author_id": "m99",
        "body": "@channel announce", "mention_ids": ["@channel"],
        "mention_kind": "broadcast_channel",
    })
    assert resp.status_code == 200

    rows = db.execute(
        "SELECT mentioned_id, successful_surfaces FROM mention_dispatch WHERE mentioner_id = %s",
        ["m99"],
    ).fetchall()
    by_member = {r[0]: set(r[1]) for r in rows}

    # m1 in DND → push must not appear in successful_surfaces.
    assert "push" not in by_member.get("m1", set()), f"push fired for DND m1: {by_member.get('m1')}"
    # m2 not in DND → push should appear (sanity that the broadcast actually reached m2).
    assert "push" in by_member.get("m2", set()), f"push missed for non-DND m2: {by_member.get('m2')}"
